function parseCsvRowNarrow(input: string): readonly [string, string, string] {
  for (let i = 0; i < input.length; i++) {
    const code = input.charCodeAt(i);
    if (code > 127) {
      throw new RangeError(`Non-ASCII character at position ${i}: code ${code}`);
    }
    if (code < 32) {
      throw new SyntaxError(`Control character at position ${i}: code ${code}`);
    }
  }

  const fields = input.split(',');

  if (fields.length !== 3) {
    throw new SyntaxError(`Expected exactly 3 comma-separated fields, got ${fields.length}`);
  }

  return [fields[0].trim(), fields[1].trim(), fields[2].trim()] as const;
}

export { parseCsvRowNarrow };
export default parseCsvRowNarrow;
